import React,{useState,useEffect} from "react";
import "./App.css";
import "./index.css";

import {Bar, Doughnut } from "react-chartjs-2";
import SubscriptionForm from "./SubscriptionForm";
//import Dashboard from "./Dashboard";
import SpendingChart from "./SpendingChart";
import PiggyBank from "./PiggyBank"; 
import FAQ from "./FAQ";
import Footer from "./Footer";


import {
Chart as ChartJS,
CategoryScale,
LinearScale,
BarElement,
ArcElement,
Title,
Tooltip,
Legend
} from "chart.js";

ChartJS.register(
CategoryScale,
LinearScale,
BarElement,
ArcElement,
Title,
Tooltip,
Legend
);

function App(){

const [transactions,setTransactions] = useState([]);
const [amount,setAmount] = useState("");
const todaySavings=transactions.reduce((total,t)=>total + t.saved, 0).toFixed(2);
const [subscriptions, setSubscriptions] = useState([]);
const [loading, setLoading] = useState(false);
const [menuOpen, setMenuOpen] = useState(false);
const [darkMode, setDarkMode] = useState(false);


useEffect(()=>{
fetchTransactions();
fetchSubscriptions();
},[]);

const fetchTransactions = async () => {
  const res = await fetch("http://localhost:5000/transactions");
  const data = await res.json();
  setTransactions(data);
};

const fetchSubscriptions = async () => {
    setLoading(true);
  try {
    const res = await fetch("http://localhost:5000/subscriptions");
    const data = await res.json();
    setSubscriptions(data);
  } catch (err) {
    console.log(err);
  }
   setLoading(false);
};

//Add Transaction
const addTransaction = async () =>{

    if (!amount || isNaN(amount)) {
  alert("Enter valid amount");
  return;
}
const res = await fetch("http://localhost:5000/transaction",{
method:"POST",
headers:{
"Content-Type":"application/json"
},
body:JSON.stringify({amount})
});
if (res.ok) {
  setAmount("");
  fetchTransactions();
  alert("Transaction Added Successfully!");
} else {
  alert("Failed to add transaction.");
}
}

//ClearTransaction
const clearTransactions =async () => {
try {
  await fetch("http://localhost:5000/clear", 
    { method: "DELETE" });    await fetch("http://localhost:5000/clear",{
        method:"DELETE" 
    });
fetchTransactions();
} catch(err) {
  console.error(err);
  alert("Failed to clear transactions");
}
}


const totalSavings =
transactions.reduce((sum,t)=>sum + t.saved,0);

const chartData = {
labels: transactions.map((t,i)=>"T"+(i+1)),
datasets:[
{
label:"Savings",
data: transactions.map(t=>t.saved),
backgroundColor: "#0e652e"
}
]
};

const goal = 1000;

const goalData = {
  labels: ["Saved", "Remaining"],
  datasets: [
    {
      data: [totalSavings, Math.max(goal - totalSavings, 0)],
      backgroundColor: ["#22c55e", "#e5e7eb"],
    },
  ],
};

const totalSubscription = subscriptions.reduce(
  (sum, sub) => sum + Number(sub.amount || 0),
  0
);

const predictedSpending = totalSubscription + totalSavings;

const progress =(totalSavings/goal)*100;

useEffect(() => {
  if (transactions.length > 5) {
  }
}, [transactions]);

useEffect(() => {
  subscriptions.forEach((sub) => {
    if (sub.amount > 1000) {
      console.log("High subscription:", sub.name);
    }
  });
}, [subscriptions]);

return (
<div className={
  darkMode 
  ? "flex flex-col md:flex-row min-h-screen bg-gray-900 text-white" 
  : "flex flex-col md:flex-row min-h-screen bg-gray-100"
}>


{/* Sidebar */}

<div
className={`bg-gray-900 text-white p-6 md:w-64 w-full absolute md:relative z-10 
${menuOpen ? "block" : "hidden"} md:block`}
>
<button
className="md:flex text-2xl"
onClick={() => setMenuOpen(!menuOpen)}
>
☰
</button>

<h2 className="text-2xl font-bold mb-10">Smart Savings</h2>
<ul className="space-y-4 text-gray-300">
<li className="hover:text-white cursor-pointer">📊 Dashboard</li>
<li className="hover:text-white cursor-pointer">💰 Transactions</li>
<li className="hover:text-white cursor-pointer">📈 Analytics</li>
<li className="hover:text-white cursor-pointer">⚙ Settings</li>
<button
className="bg-gray-200 px-3 py-1 rounded"
onClick={() => setDarkMode(!darkMode)}
>
{darkMode ? "☀ Light" : "🌙 Dark"}
</button>
</ul>
</div>
<div className="flex-1">


{/* Navbar */}
